@app.route("/tokens", methods=["POST"])
def create_token():
    data = request.get_json(silent=True) or {}
    token_value = data.get("token")
    subject = data.get("subject")
    scope = data.get("scope", "")

    if not token_value:
        return jsonify({"error": "token is required"}), 400

    existing = AccessToken.query.filter_by(token=token_value).first()
    if existing:
        return jsonify({"error": "token already exists"}), 409

    token = AccessToken(token=token_value, subject=subject, scope=scope, revoked=False)
    db.session.add(token)
    db.session.commit()

    return jsonify({
        "message": "token created",
        "token": token.to_dict()
    }), 201


@app.route("/tokens/<string:token_value>/revoke", methods=["POST"])
def revoke_token(token_value):
    token = AccessToken.query.filter_by(token=token_value).first()
    if not token:
        return jsonify({"error": "token not found"}), 404

    token.revoked = True
    db.session.commit()

    return jsonify({"message": "token revoked"}), 200


